// Dedupe to the newest brief per file_key (the REST call is ordered desc).
// Emit one item per file that changed in the window, with notification-ready fields.
const rows = $input.first().json || [];
const DASHBOARD_BASE = $env.DASHBOARD_URL || 'https://figma-comments.srv1486031.hstgr.cloud';
const seen = new Set();
const out = [];
for (const r of rows) {
  if (seen.has(r.file_key)) continue;
  seen.add(r.file_key);
  const b = r.brief || {};
  out.push({ json: {
    fileKey: r.file_key,
    fileName: (b.file && b.file.name) || r.file_key,
    openCount: r.open_count,
    commentCount: r.comment_count,
    figmaUrl: (b.file && b.file.url) || null,
    dashboardUrl: `${DASHBOARD_BASE}/?file=${encodeURIComponent(r.file_key)}`
  }});
}
return out;
